from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a single fluent sentence that summarizes all provided triples."""
    if not triples:
        return ""

    # Helper: map predicates to natural‑language clause builders
    def clause(triple: Triple) -> str:
        p = triple.predicate
        o = triple.object
        # Simple formatting for common building‑related predicates
        if p == "location":
            return f"is located in {o}"
        if p == "architect":
            return f"was designed by {o}"
        if p == "owner":
            return f"is owned by {o}"
        if p == "developer":
            return f"was developed by {o}"
        if p == "tenant" or p == "currentTenants":
            return f"is tenanted by {o}"
        if p == "floorCount":
            return f"has {o} floors"
        if p == "height":
            return f"is {o} tall"
        if p == "cost":
            return f"costs {o}"
        if p == "floorArea":
            return f"covers {o} square metres"
        if p == "buildingStartDate":
            return f"construction started in {o}"
        if p == "completionDate" or p == "inaugurationDate":
            return f"was completed in {o}"
        if p == "yearOfConstruction":
            return f"was built in {o}"
        if p == "buildingType":
            return f"is a {o}"
        if p == "architecturalStyle":
            return f"features {o}"
        if p == "address":
            return f"is situated at {o}"
        if p == "country":
            return f"is in {o}"
        if p == "state":
            return f"is in {o}"
        if p == "region":
            return f"is in {o}"
        if p == "capital":
            return f"has capital {o}"
        if p == "leader":
            return f"is led by {o}"
        if p == "leaderTitle":
            return f"has leader title {o}"
        if p == "currency":
            return f"uses the {o}"
        if p == "demonym":
            return f"its people are called {o}"
        if p == "postalCode":
            return f"has postal code {o}"
        # Fallback: generic “has” phrasing
        pred_readable = p.replace('_', ' ')
        return f"has {pred_readable} {o}"

    # Use the subject of the first triple as the main subject
    main_subject = triples[0].subject

    # Build clauses for each triple, skipping those where the subject differs from main_subject
    clauses = [clause(t) for t in triples if t.subject == main_subject]

    # If there are triples about other subjects (e.g., a capital city), treat them as subordinate clauses
    extra_clauses = []
    for t in triples:
        if t.subject != main_subject:
            # Form a short clause linking the other subject back to the main one
            extra = f"{t.subject} {clause(t)}"
            extra_clauses.append(extra)

    # Combine main clauses
    if not clauses:
        sentence_body = ""
    elif len(clauses) == 1:
        sentence_body = clauses[0]
    else:
        sentence_body = ", ".join(clauses[:-1]) + f", and {clauses[-1]}"

    # Append extra information if any
    if extra_clauses:
        extra_body = "; ".join(extra_clauses)
        full_sentence = f"{main_subject} {sentence_body}. Additionally, {extra_body}."
    else:
        full_sentence = f"{main_subject} {sentence_body}."

    # Capitalise first character
    return full_sentence[0].upper() + full_sentence[1:]

# EVOLVE-BLOCK-END

